sql:
SELECT COUNT(notification_id) AS total_notifications 
FROM notifications 
WHERE design_id = (SELECT design_id FROM designs ORDER BY last_modified DESC LIMIT 1);

SELECT design_name, created_date
FROM designs
WHERE created_by = 1001;

SELECT u.username, u.email
FROM users u
WHERE u.user_id IN (SELECT c.user_id FROM collaborations c);

SELECT design_name, status
FROM designs
WHERE design_id = 1;

SELECT DISTINCT design_id
FROM notifications
WHERE notification_status = 'unread';

SELECT user_id, username
FROM users
WHERE user_id NOT IN (SELECT DISTINCT user_id FROM collaborations);

SELECT COUNT(version_id)
FROM design_versions
WHERE design_id = (SELECT design_id FROM designs WHERE design_name = 'Design B');

SELECT AVG(compilation_time) 
FROM synthesis_results 
WHERE design_id = 1;

SELECT module_type, SUM(instance_count) AS total_instances
FROM modules
GROUP BY module_type;

external_knowledge:
- 'Parts' refer to the modules within a design;
- 'Projects' refer to the designs being worked on;
- 'Team members' are the users collaborating on the projects.
